def gen(rng, size):
    names = ['a', 'b', 'c', 'd']
    def build(depth, scope):
        if depth <= 0 or (scope and rng.random() < 0.3):
            if scope and rng.random() < 0.5:
                return rng.choice(scope)
            return str(rng.randrange(-20, 21))
        choice = rng.random()
        if choice < 0.4:
            return '(add ' + build(depth - 1, scope) + ' ' + build(depth - 1, scope) + ')'
        elif choice < 0.8:
            return '(mult ' + build(depth - 1, scope) + ' ' + build(depth - 1, scope) + ')'
        else:
            v = rng.choice(names)
            val = build(depth - 1, scope)
            newscope = scope + [v]
            body = build(depth - 1, newscope)
            return '(let ' + v + ' ' + val + ' ' + body + ')'
    expr = build(min(6, max(1, size // 2)), [])
    return [expr]

