class Solution:
    def evaluate(self, expression):
        def split_tokens(s):
            tokens = []
            depth = 0
            cur = ''
            for ch in s:
                if ch == '(': 
                    depth += 1
                    cur += ch
                elif ch == ')':
                    depth -= 1
                    cur += ch
                elif ch == ' ' and depth == 0:
                    if cur:
                        tokens.append(cur)
                        cur = ''
                else:
                    cur += ch
            if cur:
                tokens.append(cur)
            return tokens
        def ev(expr, scope):
            if expr[0] != '(': 
                if expr.lstrip('-').isdigit():
                    return int(expr)
                return scope[expr]
            body = expr[1:-1]
            tokens = split_tokens(body)
            op = tokens[0]
            if op == 'add':
                return ev(tokens[1], scope) + ev(tokens[2], scope)
            if op == 'mult':
                return ev(tokens[1], scope) * ev(tokens[2], scope)
            # let
            new_scope = dict(scope)
            i = 1
            while i + 1 < len(tokens):
                var = tokens[i]
                val = ev(tokens[i + 1], new_scope)
                new_scope[var] = val
                i += 2
            return ev(tokens[-1], new_scope)
        return ev(expression, {})

