class Solution:
    def evaluate(self, expression):
        scope = {}
        def split_tokens(s):
            tokens = []
            depth = 0
            cur = ''
            for ch in s:
                if ch == '(': 
                    depth += 1
                    cur += ch
                elif ch == ')':
                    depth -= 1
                    cur += ch
                elif ch == ' ' and depth == 0:
                    if cur:
                        tokens.append(cur)
                        cur = ''
                else:
                    cur += ch
            if cur:
                tokens.append(cur)
            return tokens
        def ev(expr):
            if expr[0] != '(': 
                if expr.lstrip('-').isdigit():
                    return int(expr)
                return scope[expr][-1]
            tokens = split_tokens(expr[1:-1])
            op = tokens[0]
            if op == 'add':
                return ev(tokens[1]) + ev(tokens[2])
            if op == 'mult':
                return ev(tokens[1]) * ev(tokens[2])
            assigned = []
            i = 1
            while i + 1 < len(tokens):
                var = tokens[i]
                val = ev(tokens[i + 1])
                scope.setdefault(var, []).append(val)
                assigned.append(var)
                i += 2
            result = ev(tokens[-1])
            for var in assigned:
                scope[var].pop()
            return result
        return ev(expression)

