var evaluate = function(expression) {
    const scope = new Map();
    function splitTokens(s) {
        const tokens = [];
        let depth = 0, cur = '';
        for (const ch of s) {
            if (ch === '(') { depth++; cur += ch; }
            else if (ch === ')') { depth--; cur += ch; }
            else if (ch === ' ' && depth === 0) { if (cur) { tokens.push(cur); cur = ''; } }
            else cur += ch;
        }
        if (cur) tokens.push(cur);
        return tokens;
    }
    function isInt(t) { return /^-?\d+$/.test(t); }
    function ev(expr) {
        if (expr[0] !== '(') {
            if (isInt(expr)) return parseInt(expr, 10);
            const stack = scope.get(expr);
            return stack[stack.length - 1];
        }
        const tokens = splitTokens(expr.slice(1, -1));
        const op = tokens[0];
        if (op === 'add') return ev(tokens[1]) + ev(tokens[2]);
        if (op === 'mult') return ev(tokens[1]) * ev(tokens[2]);
        const assigned = [];
        let i = 1;
        while (i + 1 < tokens.length) {
            const v = tokens[i];
            const val = ev(tokens[i + 1]);
            if (!scope.has(v)) scope.set(v, []);
            scope.get(v).push(val);
            assigned.push(v);
            i += 2;
        }
        const result = ev(tokens[tokens.length - 1]);
        for (const v of assigned) scope.get(v).pop();
        return result;
    }
    return ev(expression);
};
